```go
package main

import (
	"fmt"
	"net/http"
)

func main() {
	// Create a new HTTP server
	server := http.NewServeMux()

	// Register routes
	registerRoutes(server)

	// Start the server
	err := http.ListenAndServe(":8080", server)
	if err != nil {
		fmt.Println("Error starting the server:", err)
	}
}

func registerRoutes(server *http.ServeMux) {
	for i := 0; i < 500; i++ {
		path := fmt.Sprintf("/route%d", i)
		server.HandleFunc(path, handleRequest)
	}
}

func handleRequest(w http.ResponseWriter, r *http.Request) {
	// Handle the request
	fmt.Fprint(w, "Hello from the server!")
}
```

In this example, we create an HTTP server using `http.NewServeMux`, and then use a loop to register 500 different routes using `server.HandleFunc`. Each route corresponds to a unique URL path, such as `/route1`, `/route2`, and so on.

The `handleRequest` function is called for every incoming request and simply responds with the message "Hello from the server!".

