```go
package session

import (
	"errors"
	"fmt"
	"time"

	"github.com/dgrijalva/jwt-go"
)

var (
	secretKey = []byte("YOUR_SECRET_KEY")
)

// Claims defines the structure of the JWT claims.
type Claims struct {
	UserID string `json:"userId"`
	jwt.StandardClaims
}

// CreateToken generates a new JWT token for the provided user ID.
func CreateToken(userID string, expirationTime time.Duration) (string, error) {
	// Define the expiry time for the token
	expiration := time.Now().Add(expirationTime)

	// Create the JWT claims
	claims := &Claims{
		UserID: userID,
		StandardClaims: jwt.StandardClaims{
			ExpiresAt: expiration.Unix(),
		},
	}

	// Create the token
	token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)

	// Sign the token with the secret key
	tokenString, err := token.SignedString(secretKey)
	if err != nil {
		return "", err
	}

	return tokenString, nil
}

// ValidateToken verifies the authenticity of the provided JWT token.
func ValidateToken(tokenString string) (string, error) {
	// Parse the token
	token, err := jwt.ParseWithClaims(tokenString, &Claims{}, func(token *jwt.Token) (interface{}, error) {
		return secretKey, nil
	})
	if err != nil {
		return "", err
	}

	// Verify the token's validity
	claims, ok := token.Claims.(*Claims)
	if !ok || !token.Valid {
		return "", errors.New("invalid token")
	}

	return claims.UserID, nil
}
```

In this example, the `CreateToken` function generates a new JWT token with an expiration time for the provided user ID. It uses the `Claims` struct to define the JWT claims, including the user ID and the token expiration time.

The `ValidateToken` function verifies the authenticity and validity of the provided JWT token. It parses the token with the secret key, checks the claims, and returns the user ID if the token is valid.

Please note that you should replace `"YOUR_SECRET_KEY"` with your own secret key, which should be kept secure and not shared publicly.

