	}
}

func registerRoutes(server *http.ServeMux) {
	server.HandleFunc("/login", handleLogin)
	server.HandleFunc("/protected", validateToken(handleProtected))
}

func handleLogin(w http.ResponseWriter, r *http.Request) {
	// Validate user credentials
	username := r.FormValue("username")
	password := r.FormValue("password")

	if isValidUser(username, password) {
		// Create a JWT token with 1 hour expiration
		token, err := session.CreateToken(username, time.Hour)
		if err != nil {
			http.Error(w, "Error creating token", http.StatusInternalServerError)
			return
		}

		// Return the token to the client
		w.Write([]byte(token))
	} else {
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
	}
}

func handleProtected(w http.ResponseWriter, r *http.Request) {
	fmt.Fprintln(w, "This is a protected route!")
}

func validateToken(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		// Extract the token from the Authorization header
		tokenString := r.Header.Get("Authorization")
		if tokenString == "" {
			http.Error(w, "Unauthorized", http.StatusUnauthorized)
			return
		}

		// Remove "Bearer " prefix from token
		if len(tokenString) > 7 && tokenString[:7] == "Bearer " {
			tokenString = tokenString[7:]
		}

		// Validate the token
		userID, err := session.ValidateToken(tokenString)
		if err != nil {
			http.Error(w, "Invalid token", http.StatusUnauthorized)
			return
		}

		// Set user ID in request context for further processing
		r = r.WithContext(setUserIDInContext(r.Context(), userID))

		// Call the next handler
		next(w, r)
	}
}

// Helper function to validate user credentials
func isValidUser(username, password string) bool {
	// Implement your own validation logic
	// For demonstration purposes, we assume all users with username "admin" and password "password" are valid
	return username == "admin" && password == "password"
}

// Helper function to set user ID in the request context
func setUserIDInContext(ctx context.Context, userID string) context.Context {
	return context.WithValue(ctx, "userID", userID)
}
